import { createHmac, timingSafeEqual } from "node:crypto";
import { cookies } from "next/headers";
import { redirect } from "next/navigation";

export type ChatGPTUser = {
  displayName: string;
  email: string;
  fullName: string | null;
};

export const ADMIN_COOKIE = "ulucan_admin";
const SIGN_IN_PATH = "/yonetim/giris";
const SIGN_OUT_PATH = "/api/admin/logout";

function safeEqual(left: string, right: string) {
  const a = Buffer.from(left);
  const b = Buffer.from(right);
  return a.length === b.length && timingSafeEqual(a, b);
}

function signature(email: string) {
  const secret = process.env.ADMIN_SESSION_SECRET || "";
  if (secret.length < 32) return "";
  return createHmac("sha256", secret).update(email).digest("hex");
}

export function createAdminSession(email: string, password: string): string | null {
  const allowed = String(process.env.ADMIN_EMAILS || "").split(",").map((item) => item.trim().toLowerCase()).filter(Boolean);
  const normalized = email.trim().toLowerCase();
  if (!allowed.includes(normalized) || !process.env.ADMIN_PASSWORD || !safeEqual(password, process.env.ADMIN_PASSWORD)) return null;
  const encoded = Buffer.from(normalized, "utf8").toString("base64url");
  return `${encoded}.${signature(normalized)}`;
}

export async function getChatGPTUser(): Promise<ChatGPTUser | null> {
  const token = (await cookies()).get(ADMIN_COOKIE)?.value;
  if (!token) return null;
  const [encoded, suppliedSignature] = token.split(".");
  if (!encoded || !suppliedSignature) return null;
  let email = "";
  try { email = Buffer.from(encoded, "base64url").toString("utf8").toLowerCase(); } catch { return null; }
  const expected = signature(email);
  if (!expected || !safeEqual(suppliedSignature, expected)) return null;
  return { displayName: email, email, fullName: null };
}

export async function requireChatGPTUser(returnTo: string): Promise<ChatGPTUser> {
  const user = await getChatGPTUser();
  if (user) return user;
  redirect(chatGPTSignInPath(returnTo));
}

export function chatGPTSignInPath(returnTo: string): string {
  return `${SIGN_IN_PATH}?return_to=${encodeURIComponent(safeRelativeReturnPath(returnTo))}`;
}

export function chatGPTSignOutPath(returnTo = "/"): string {
  return `${SIGN_OUT_PATH}?return_to=${encodeURIComponent(safeRelativeReturnPath(returnTo))}`;
}

function safeRelativeReturnPath(value: string): string {
  if (!value.startsWith("/") || value.startsWith("//")) return "/";
  try {
    const url = new URL(value, "https://app.local");
    if (url.origin !== "https://app.local" || url.pathname === SIGN_OUT_PATH) return "/";
    return `${url.pathname}${url.search}${url.hash}`;
  } catch {
    return "/";
  }
}
