import Link from "next/link";
import { requireChatGPTUser } from "../../chatgpt-auth";
import { getAdminUser } from "@/lib/admin-auth";
import { getQuoteRequests } from "@/lib/content-store";

export const dynamic = "force-dynamic";
const formatDate = (value: string) => new Intl.DateTimeFormat("tr-TR", { dateStyle: "short", timeStyle: "short", timeZone: "Europe/Istanbul" }).format(new Date(value));

export default async function QuoteRequestsPage() {
  await requireChatGPTUser("/yonetim/teklifler");
  const auth = await getAdminUser();
  if (!auth.allowed) return <main className="admin-shell"><p className="admin-notice">Bu alana erişim izniniz yok.</p></main>;
  const requests = await getQuoteRequests();
  return <main className="admin-shell"><div className="admin-top"><div><p className="eyebrow"><span>UH</span>Satış talepleri</p><h1>Teklif Talepleri</h1></div><Link className="text-link" href="/yonetim">Yönetime dön <span>←</span></Link></div>
    <section className="analytics-panel"><p className="analytics-note">İletişim formundan gelen son 250 talep. Gönderimler hız sınırı, zaman kontrolü ve görünmez spam alanıyla korunur.</p><div className="table-wrap"><table><thead><tr><th>No</th><th>Tarih</th><th>Ad / Firma</th><th>İletişim</th><th>Proje</th><th>Konum</th><th>Talep</th></tr></thead><tbody>{requests.map((item, index) => <tr key={item.id}><td>{String(index + 1).padStart(3, "0")}</td><td>{formatDate(item.createdAt)}</td><td><strong>{item.name}</strong><br />{item.company}</td><td>{item.phone}<br />{item.email}</td><td>{item.projectType}</td><td>{item.location}</td><td className="quote-message-cell">{item.message}</td></tr>)}</tbody></table></div>{requests.length === 0 && <p>Henüz teklif talebi yok.</p>}</section>
  </main>;
}
